async (params, browser) => {
  // Open page
  await browser.open('https://www.myfitnesspal.com/recipes')

  // Wait for content
  await browser.waitForSelector('[class*="recipe"], .recipe-card, article', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const recipes = Array.from(document.querySelectorAll('[class*="recipe"], .recipe-card, article')).slice(0,20).map(el => { const title = el.querySelector('h2, h3, a, [class*="title"]')?.textContent?.trim()||''; const cal = el.querySelector('[class*="calories"], .nutrition-info')?.textContent?.trim()||''; const link = el.querySelector('a')?.href||''; return { title, calories: cal, url: link }; }).filter(r=>r.title); return { recipes, url: window.location.href }`)

  return page_data
}
